mapper.select:
select 
from im_room_message
where room_id = #{roomId, jdbcType=BINARY}
  and from_user_id = #{fromUserId, jdbcType=BINARY}
  and client_msg_id = #{clientMsgId}

select 
from im_room_message
where room_id = #{roomId, jdbcType=BINARY}
  and seq > #{afterSeqExclusive}
order by seq asc
limit #{limit}
